import * as React from "react";

type Variant = "primary" | "secondary" | "ghost";
type Size = "sm" | "md" | "lg";

export interface TdButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: Variant;
  size?: Size;
  asChild?: boolean;
}

const sizeClasses: Record<Size, string> = {
  sm: "h-9 px-3 text-sm",
  md: "h-10 px-5 text-base",
  lg: "h-12 px-7 text-lg",
};

const base =
  "inline-flex items-center justify-center rounded-md font-medium tracking-tight transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-[var(--td-primary,theme(colors.slate.900))] disabled:opacity-50 disabled:pointer-events-none";

function variantStyle(variant: Variant): React.CSSProperties {
  if (variant === "primary") {
    return {
      backgroundColor: "var(--td-primary, #2E6554)",
      color: "var(--td-on-primary, #ffffff)",
    };
  }
  if (variant === "secondary") {
    return {
      backgroundColor: "var(--td-secondary, #234F98)",
      color: "var(--td-on-secondary, #ffffff)",
    };
  }
  return {
    backgroundColor: "transparent",
    color: "var(--td-primary, #2E6554)",
    borderColor: "var(--td-primary, #2E6554)",
  };
}

export const TdButton = React.forwardRef<HTMLButtonElement, TdButtonProps>(
  ({ variant = "primary", size = "md", className = "", style, children, ...props }, ref) => {
    const ghostBorder = variant === "ghost" ? "border" : "";
    return (
      <button
        ref={ref}
        className={`${base} ${sizeClasses[size]} ${ghostBorder} ${className}`.trim()}
        style={{ ...variantStyle(variant), ...style }}
        {...props}
      >
        {children}
      </button>
    );
  }
);
TdButton.displayName = "TdButton";

export default TdButton;
